SELECT paper_id, title
FROM papers
ORDER BY times_cited_all_databases DESC;

SELECT title
FROM papers
WHERE paper_id = 1;

SELECT title, times_cited_all_databases
FROM papers
ORDER BY times_cited_all_databases DESC;

SELECT times_cited_all_databases AS total_citations
  FROM papers
  WHERE paper_id = 1;

SELECT title
FROM papers
ORDER BY times_cited_all_databases DESC;
